import { AssignmentType, Resident } from './types';

export const TOTAL_WEEKS = 52;
export const COHORT_COUNT = 5;

// Initial Data Generation Helpers
export const GENERATE_INITIAL_RESIDENTS = (): Resident[] => {
  const residents: Resident[] = [];

  // 15 PGY1 (Numbers 1-15)
  for (let i = 1; i <= 15; i++) {
    residents.push({
      id: `pgy1-${i}`,
      name: `${i}. Intern (PGY1)`,
      level: 1,
      cohort: (i - 1) % COHORT_COUNT,
      avoidResidentIds: [],
    });
  }

  // 14 PGY2 (Numbers 16-29)
  for (let i = 16; i <= 29; i++) {
    residents.push({
      id: `pgy2-${i}`,
      name: `${i}. Resident (PGY2)`,
      level: 2,
      cohort: (i - 1) % COHORT_COUNT, 
      avoidResidentIds: [],
    });
  }

  // 9 PGY3 (Numbers 30-38)
  for (let i = 30; i <= 38; i++) {
    residents.push({
      id: `pgy3-${i}`,
      name: `${i}. Senior (PGY3)`,
      level: 3,
      cohort: (i - 1) % COHORT_COUNT,
      avoidResidentIds: [],
    });
  }

  return residents;
};

export const ASSIGNMENT_COLORS: Record<AssignmentType, string> = {
  [AssignmentType.WARDS_RED]: 'bg-red-200 text-red-900 border-red-300',
  [AssignmentType.WARDS_BLUE]: 'bg-blue-200 text-blue-900 border-blue-300',
  [AssignmentType.ICU]: 'bg-purple-200 text-purple-900 border-purple-300',
  [AssignmentType.NIGHT_FLOAT]: 'bg-indigo-600 text-white border-indigo-700',
  [AssignmentType.EM]: 'bg-orange-200 text-orange-900 border-orange-300',
  [AssignmentType.CLINIC]: 'bg-yellow-100 text-yellow-800 border-yellow-200',
  [AssignmentType.ELECTIVE]: 'bg-green-100 text-green-800 border-green-200',
  [AssignmentType.VACATION]: 'bg-gray-100 text-gray-400 border-gray-200',
  [AssignmentType.MET_WARDS]: 'bg-teal-100 text-teal-800 border-teal-200',
};

export const ASSIGNMENT_LABELS: Record<AssignmentType, string> = {
  [AssignmentType.WARDS_RED]: 'Wards Red',
  [AssignmentType.WARDS_BLUE]: 'Wards Blue',
  [AssignmentType.ICU]: 'ICU',
  [AssignmentType.NIGHT_FLOAT]: 'Night Float',
  [AssignmentType.EM]: 'Emergency',
  [AssignmentType.CLINIC]: 'Clinic (CCIM)',
  [AssignmentType.ELECTIVE]: 'Elective',
  [AssignmentType.VACATION]: 'Vacation',
  [AssignmentType.MET_WARDS]: 'Met Wards',
};

import { Resident, ScheduleGrid, AssignmentType, ScheduleCell, ScheduleStats } from '../types';
import { TOTAL_WEEKS, COHORT_COUNT } from '../constants';

// Helper to count specific assignments for a resident so far to balance load
const getCount = (schedule: ScheduleGrid, residentId: string, type: AssignmentType): number => {
  return schedule[residentId].filter(cell => cell.assignment === type).length;
};

// Check if a resident is available for a contiguous block of weeks
const isAvailableForBlock = (
  schedule: ScheduleGrid, 
  residentId: string, 
  startWeek: number, 
  duration: number
): boolean => {
  if (startWeek + duration > TOTAL_WEEKS) return false;

  for (let i = 0; i < duration; i++) {
    const w = startWeek + i;
    // Must be empty and not locked (Assignment check handles Clinic which is pre-filled)
    if (schedule[residentId][w].assignment !== null) {
      return false;
    }
  }
  return true;
};

export const generateSchedule = (
  residents: Resident[], 
  existingSchedule: ScheduleGrid
): ScheduleGrid => {
  // Deep copy existing schedule
  const newSchedule: ScheduleGrid = JSON.parse(JSON.stringify(existingSchedule));

  // Initialize empty grid if needed
  residents.forEach(r => {
    if (!newSchedule[r.id] || newSchedule[r.id].length !== TOTAL_WEEKS) {
      newSchedule[r.id] = Array(TOTAL_WEEKS).fill({ assignment: null, locked: false });
    } else {
      // Clear non-locked assignments to regenerate fresh
      newSchedule[r.id] = newSchedule[r.id].map(cell => 
        cell.locked ? cell : { assignment: null, locked: false }
      );
    }
  });

  // 1. PLACE COHORT CLINICS (Fixed Constraints)
  // 4+1 Schedule: Cohort 0 is CCIM week 0, 5, 10...
  residents.forEach(resident => {
    for (let w = 0; w < TOTAL_WEEKS; w++) {
      if (w % COHORT_COUNT === resident.cohort) {
        if (!newSchedule[resident.id][w].locked) {
          newSchedule[resident.id][w] = { assignment: AssignmentType.CLINIC, locked: false };
        }
      }
    }
  });

  // Definition of assignments with block durations and staffing requirements
  const assignmentsToCheck = [
    { 
      type: AssignmentType.WARDS_RED, 
      duration: 4, 
      minInterns: 2, maxInterns: 2, 
      minSeniors: 2, maxSeniors: 2 
    },
    { 
      type: AssignmentType.WARDS_BLUE, 
      duration: 4, 
      minInterns: 2, maxInterns: 2, 
      minSeniors: 2, maxSeniors: 2 
    },
    { 
      type: AssignmentType.ICU, 
      duration: 4, 
      minInterns: 2, maxInterns: 2, 
      minSeniors: 2, maxSeniors: 2 
    },
    { 
      type: AssignmentType.NIGHT_FLOAT, 
      duration: 4, 
      minInterns: 1, maxInterns: 1, 
      minSeniors: 1, maxSeniors: 1 
    },
    { 
      type: AssignmentType.EM, 
      duration: 2, // 2 week blocks for flexibility
      minInterns: 1, maxInterns: 2, // Allow up to 2
      minSeniors: 1, maxSeniors: 2 
    }
  ];

  // Helper to assign a block
  const assignBlock = (
    week: number, 
    type: AssignmentType, 
    duration: number, 
    levelFilter: (l: number) => boolean,
    neededCount: number,
    currentAssigned: Resident[]
  ) => {
    // Determine how many we still need
    // We count how many in 'currentAssigned' match the level filter
    const currentCount = currentAssigned.filter(r => levelFilter(r.level)).length;
    let slotsToFill = neededCount - currentCount;

    while (slotsToFill > 0) {
      // Find Candidates
      const candidates = residents.filter(r => 
        levelFilter(r.level) && 
        isAvailableForBlock(newSchedule, r.id, week, duration)
      );

      if (candidates.length === 0) break; // No one available

      // Scoring:
      // 1. Avoid conflicts (avoidResidentIds)
      // 2. Balance workload (count of this assignment type)
      // 3. Randomness
      candidates.sort((a, b) => {
        // Conflict Check
        const aConflicts = currentAssigned.some(existing => a.avoidResidentIds.includes(existing.id) || existing.avoidResidentIds.includes(a.id));
        const bConflicts = currentAssigned.some(existing => b.avoidResidentIds.includes(existing.id) || existing.avoidResidentIds.includes(b.id));
        if (aConflicts && !bConflicts) return 1;
        if (!aConflicts && bConflicts) return -1;

        // Workload Balance
        const countA = getCount(newSchedule, a.id, type);
        const countB = getCount(newSchedule, b.id, type);
        if (countA !== countB) return countA - countB;

        return Math.random() - 0.5;
      });

      const selected = candidates[0];

      // Assign the block
      for (let i = 0; i < duration; i++) {
        newSchedule[selected.id][week + i] = { assignment: type, locked: false };
      }

      currentAssigned.push(selected);
      slotsToFill--;
    }
  };

  // 2. FILL REQUIRED ROTATIONS WITH BLOCKS
  // We iterate through weeks. If a service is understaffed at week W, we try to start a block at week W.

  for (let w = 0; w < TOTAL_WEEKS; w++) {
    for (const job of assignmentsToCheck) {
      // Check current staffing at this exact week `w`
      // Optimization: Only check start of blocks? No, because blocks overlap.
      // We check if we need to *start* a block here to cover a gap.
      // Actually, simplest greedy packing:
      // Count how many people are assigned to this job at week `w`.

      const assignedResidents = residents.filter(r => 
        newSchedule[r.id][w]?.assignment === job.type
      );

      // INTERNS
      const internCount = assignedResidents.filter(r => r.level === 1).length;
      if (internCount < job.minInterns) {
        // Try to start a block here
        assignBlock(w, job.type, job.duration, (l) => l === 1, job.minInterns, assignedResidents);
      }

      // SENIORS (PGY2/3)
      const seniorCount = assignedResidents.filter(r => r.level > 1).length;
      if (seniorCount < job.minSeniors) {
        assignBlock(w, job.type, job.duration, (l) => l > 1, job.minSeniors, assignedResidents);
      }
    }
  }

  // 3. FILL GAPS WITH ELECTIVES/VACATION
  residents.forEach(r => {
    for (let w = 0; w < TOTAL_WEEKS; w++) {
      if (!newSchedule[r.id][w].assignment) {
        // Randomly assign vacation (approx 4 weeks a year)
        const vacCount = getCount(newSchedule, r.id, AssignmentType.VACATION);
        // Ensure vacation doesn't break a future block? 
        // Logic simplifies here: if it's empty now, it wasn't needed for a required block.
        if (vacCount < 4 && Math.random() > 0.9) {
          newSchedule[r.id][w] = { assignment: AssignmentType.VACATION, locked: false };
        } else {
          newSchedule[r.id][w] = { assignment: AssignmentType.ELECTIVE, locked: false };
        }
      }
    }
  });

  return newSchedule;
};

export const calculateStats = (residents: Resident[], schedule: ScheduleGrid): ScheduleStats => {
  const stats: ScheduleStats = {};

  residents.forEach(r => {
    stats[r.id] = {
      [AssignmentType.WARDS_RED]: 0,
      [AssignmentType.WARDS_BLUE]: 0,
      [AssignmentType.ICU]: 0,
      [AssignmentType.NIGHT_FLOAT]: 0,
      [AssignmentType.EM]: 0,
      [AssignmentType.CLINIC]: 0,
      [AssignmentType.ELECTIVE]: 0,
      [AssignmentType.VACATION]: 0,
      [AssignmentType.MET_WARDS]: 0,
    };

    if (schedule[r.id]) {
      schedule[r.id].forEach(cell => {
        if (cell.assignment && stats[r.id][cell.assignment] !== undefined) {
          stats[r.id][cell.assignment]++;
        }
      });
    }
  });

  return stats;
};

