  for (let w = 0; w < TOTAL_WEEKS; w++) {
    for (const job of assignmentsToCheck) {
      // Check current staffing at this exact week `w`

      const assignedResidents = residents.filter(r => 
        newSchedule[r.id][w]?.assignment === job.type
      );

      // INTERNS
      const internCount = assignedResidents.filter(r => r.level === 1).length;
      if (internCount < job.minInterns) {
        // Try to start a block here
        assignBlock(w, job.type, job.duration, (l) => l === 1, job.minInterns, assignedResidents);
      }

      // SENIORS (PGY2/3)
      const seniorCount = assignedResidents.filter(r => r.level > 1).length;
      if (seniorCount < job.minSeniors) {
        assignBlock(w, job.type, job.duration, (l) => l > 1, job.minSeniors, assignedResidents);
      }
    }
  }

  // 3. FILL GAPS WITH ELECTIVES/VACATION
  residents.forEach(r => {
    // First pass: Identify and fill 2-week blocks with Electives
    for (let w = 0; w < TOTAL_WEEKS - 1; w++) {
        // Skip if current week is filled (Clinic, Wards, etc.)
        if (newSchedule[r.id][w].assignment) continue;

        // Check next week availability for a 2-week block
        if (!newSchedule[r.id][w+1].assignment) {
            // Found a 2-week gap: Assign Elective Pair
            newSchedule[r.id][w] = { assignment: AssignmentType.ELECTIVE, locked: false };
            newSchedule[r.id][w+1] = { assignment: AssignmentType.ELECTIVE, locked: false };
            // Note: Next loop iteration for w+1 will see it assigned and skip
        }
    }

    // Second pass: Fill remaining single gaps
    let vacCount = getCount(newSchedule, r.id, AssignmentType.VACATION);

    for (let w = 0; w < TOTAL_WEEKS; w++) {
        if (!newSchedule[r.id][w].assignment) {
             // Prioritize filling single gaps with Vacation to reach quota (approx 4)
             if (vacCount < 4) {
                 newSchedule[r.id][w] = { assignment: AssignmentType.VACATION, locked: false };
                 vacCount++;
             } else {
                 newSchedule[r.id][w] = { assignment: AssignmentType.ELECTIVE, locked: false };
             }
        }
    }

    // Third pass: Ensure minimum vacation if single gaps weren't enough
    // If vacCount is still low, we must cannibalize some Electives.
    if (vacCount < 4) {
        for (let w = 0; w < TOTAL_WEEKS && vacCount < 4; w++) {
            if (newSchedule[r.id][w].assignment === AssignmentType.ELECTIVE && !newSchedule[r.id][w].locked) {
                newSchedule[r.id][w].assignment = AssignmentType.VACATION;
                vacCount++;
            }
        }
    }
  });

  return newSchedule;
};

