export const GENERATE_INITIAL_RESIDENTS = (): Resident[] => {
  const residents: Resident[] = [];

  // 15 PGY1 (Numbers 1-15)
  for (let i = 1; i <= 15; i++) {
    residents.push({
      id: `pgy1-${i}`,
      name: `${i}. Intern (PGY1)`,
      level: 1,
      cohort: (i - 1) % COHORT_COUNT,
      avoidResidentIds: [],
    });
  }

  // 14 PGY2 (Numbers 16-29)
  for (let i = 16; i <= 29; i++) {
    residents.push({
      id: `pgy2-${i}`,
      name: `${i}. Resident (PGY2)`,
      level: 2,
      cohort: (i - 1) % COHORT_COUNT, 
      avoidResidentIds: [],
    });
  }

  // 9 PGY3 (Numbers 30-38)
  for (let i = 30; i <= 38; i++) {
    residents.push({
      id: `pgy3-${i}`,
      name: `${i}. Senior (PGY3)`,
      level: 3,
      cohort: (i - 1) % COHORT_COUNT,
      avoidResidentIds: [],
    });
  }

  return residents;
};

