  // 9 PGY3 (Numbers 30-38)
  for (let i = 30; i <= 38; i++) {
    residents.push({
      id: `pgy3-${i}`,
      name: `${i}. Senior (PGY3)`,
      level: 3,
      cohort: (i - 1) % COHORT_COUNT,
      avoidResidentIds: [],
    });
  }

  return residents;
};

