            <Bar dataKey={AssignmentType.ENT} stackId="a" fill="#99f6e4" name="ENT" />

            <Bar dataKey={AssignmentType.ELECTIVE} stackId="a" fill="#86efac" name="Elective" />
            <Bar dataKey={AssignmentType.VACATION} stackId="a" fill="#e5e7eb" name="Vacation" />
            <Bar dataKey={AssignmentType.MET_WARDS} stackId="a" fill="#99f6e4" name="Met Wards" />
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );

  return (
    <div className="p-6 bg-gray-50 min-h-full">
      <ChartSection title="PGY 1 (Interns)" dataSet={pgy1Data} />
      <ChartSection title="PGY 2" dataSet={pgy2Data} />
      <ChartSection title="PGY 3" dataSet={pgy3Data} />
    </div>
  );
};

import { Resident, ScheduleGrid, AssignmentType, ScheduleCell, ScheduleStats, CohortFairnessMetrics, ResidentFairnessMetrics } from '../types';
import { TOTAL_WEEKS, COHORT_COUNT, ROTATION_METADATA, CORE_TYPES, REQUIRED_TYPES, ELECTIVE_TYPES, VACATION_TYPE } from '../constants';

// Helper to count specific assignments for a resident so far to balance load
const getCount = (schedule: ScheduleGrid, residentId: string, type: AssignmentType): number => {
  return schedule[residentId].filter(cell => cell.assignment === type).length;
};

// Check if a resident is available for a contiguous block of weeks
const isAvailableForBlock = (
  schedule: ScheduleGrid, 
  residentId: string, 
  startWeek: number, 
  duration: number
): boolean => {
  if (startWeek + duration > TOTAL_WEEKS) return false;

  for (let i = 0; i < duration; i++) {
    const w = startWeek + i;
    // Must be empty and not locked (Assignment check handles Clinic which is pre-filled)
    if (schedule[residentId][w].assignment !== null) {
      return false;
    }
  }
  return true;
};

// Check intensity of adjacent weeks to prevent burnout
// Returns a penalty score (Higher is bad)
const checkIntensityBalance = (
    schedule: ScheduleGrid,
    residentId: string,
    startWeek: number,
    duration: number,
    currentIntensity: number
): number => {
    let penalty = 0;

    // Check week immediately before
    const prevWeek = startWeek - 1;
    if (prevWeek >= 0) {
        const prevAssign = schedule[residentId]?.[prevWeek]?.assignment;
        if (prevAssign) {
            const prevInt = ROTATION_METADATA[prevAssign].intensity;
            if (prevInt >= 3 && currentIntensity >= 3) {
                // Back-to-back intense blocks
                penalty += 100 * (prevInt + currentIntensity); 
            }
        }
    }

    // Check week immediately after (if already assigned, though generation usually moves forward, but we might have fixed blocks)
    const nextWeek = startWeek + duration;
    if (nextWeek < TOTAL_WEEKS) {
        const nextAssign = schedule[residentId]?.[nextWeek]?.assignment;
        if (nextAssign) {
            const nextInt = ROTATION_METADATA[nextAssign].intensity;
            if (nextInt >= 3 && currentIntensity >= 3) {
                penalty += 100 * (nextInt + currentIntensity);
            }
        }
    }

    return penalty;
};

export const generateSchedule = (
  residents: Resident[], 
  existingSchedule: ScheduleGrid
): ScheduleGrid => {
  // Deep copy existing schedule
  const newSchedule: ScheduleGrid = JSON.parse(JSON.stringify(existingSchedule));

  // Initialize empty grid if needed
  residents.forEach(r => {
    if (!newSchedule[r.id] || newSchedule[r.id].length !== TOTAL_WEEKS) {
      newSchedule[r.id] = Array(TOTAL_WEEKS).fill({ assignment: null, locked: false });
    } else {
      // Clear non-locked assignments to regenerate fresh
      newSchedule[r.id] = newSchedule[r.id].map(cell => 
        cell.locked ? cell : { assignment: null, locked: false }
      );
    }
  });

  // 1. PLACE COHORT CLINICS (Fixed Constraints)
  residents.forEach(resident => {
    for (let w = 0; w < TOTAL_WEEKS; w++) {
      if (w % COHORT_COUNT === resident.cohort) {
        if (!newSchedule[resident.id][w].locked) {
          newSchedule[resident.id][w] = { assignment: AssignmentType.CLINIC, locked: false };
        }
      }
    }
  });

  // HELPER: Assign Block
  // targetWeeks can now be a number OR a function that resolves the target for a specific resident
  const assignBlock = (
    week: number, 
    type: AssignmentType, 
    duration: number, 
    levelFilter: (l: number) => boolean,
    minNeeded: number, 
    maxAllowed: number,
    targetWeeks: number | ((r: Resident) => number) | undefined,
    currentAssigned: Resident[]
  ): number => {
    let filledCount = 0;
    const meta = ROTATION_METADATA[type];

    // PHASE 1: FILL MINIMUM REQUIREMENTS
    while (filledCount < minNeeded) {
      const candidates = residents.filter(r => 
        levelFilter(r.level) && 
        isAvailableForBlock(newSchedule, r.id, week, duration)
      );

      if (candidates.length === 0) break;

      candidates.sort((a, b) => {
        // 1. Target Completion
        const countA = getCount(newSchedule, a.id, type);
        const countB = getCount(newSchedule, b.id, type);

        // Resolve dynamic targets
        const targetA = typeof targetWeeks === 'function' ? targetWeeks(a) : targetWeeks;
        const targetB = typeof targetWeeks === 'function' ? targetWeeks(b) : targetWeeks;

        if (targetA !== undefined && targetB !== undefined) {
          const aMet = countA >= targetA;
          const bMet = countB >= targetB;
          if (aMet && !bMet) return 1;
          if (!aMet && bMet) return -1;
        }

        // 2. Conflict Avoidance
        const aConflicts = currentAssigned.some(existing => a.avoidResidentIds.includes(existing.id) || existing.avoidResidentIds.includes(a.id));
        const bConflicts = currentAssigned.some(existing => b.avoidResidentIds.includes(existing.id) || existing.avoidResidentIds.includes(b.id));
        if (aConflicts && !bConflicts) return 1;
        if (!aConflicts && bConflicts) return -1;

        // 3. Intensity / Balance (New Logic)
        const penaltyA = checkIntensityBalance(newSchedule, a.id, week, duration, meta.intensity);
        const penaltyB = checkIntensityBalance(newSchedule, b.id, week, duration, meta.intensity);
        if (penaltyA !== penaltyB) return penaltyA - penaltyB;

        // 4. Workload Balance
        if (countA !== countB) return countA - countB;

        return Math.random() - 0.5;
      });

      const selected = candidates[0];
      for (let i = 0; i < duration; i++) {
        newSchedule[selected.id][week + i] = { assignment: type, locked: false };
      }
      currentAssigned.push(selected);
      filledCount++;
    }

    // PHASE 2: FILL EXTRA CAPACITY (UP TO MAX)
    while (filledCount < maxAllowed) {
      const candidates = residents.filter(r => {
        if (!levelFilter(r.level)) return false;
        if (!isAvailableForBlock(newSchedule, r.id, week, duration)) return false;

        const target = typeof targetWeeks === 'function' ? targetWeeks(r) : targetWeeks;
        if (target !== undefined) {
           const current = getCount(newSchedule, r.id, type);
           if (current + duration > target) return false;
        }
        return true;
      });

      if (candidates.length === 0) break;

      candidates.sort((a, b) => {
        const countA = getCount(newSchedule, a.id, type);
        const countB = getCount(newSchedule, b.id, type);

        const aConflicts = currentAssigned.some(existing => a.avoidResidentIds.includes(existing.id) || existing.avoidResidentIds.includes(a.id));
        const bConflicts = currentAssigned.some(existing => b.avoidResidentIds.includes(existing.id) || existing.avoidResidentIds.includes(b.id));
        if (aConflicts && !bConflicts) return 1;
        if (!aConflicts && bConflicts) return -1;

        const penaltyA = checkIntensityBalance(newSchedule, a.id, week, duration, meta.intensity);
        const penaltyB = checkIntensityBalance(newSchedule, b.id, week, duration, meta.intensity);
        if (penaltyA !== penaltyB) return penaltyA - penaltyB;

        if (countA !== countB) return countA - countB;
        return Math.random() - 0.5;
      });

      const selected = candidates[0];
      for (let i = 0; i < duration; i++) {
        newSchedule[selected.id][week + i] = { assignment: type, locked: false };
      }
      currentAssigned.push(selected);
      filledCount++;
    }

    return filledCount;
  };

  // 2. NIGHT FLOAT ASSIGNMENT
  const nfMeta = ROTATION_METADATA[AssignmentType.NIGHT_FLOAT];
  // Dynamic target resolver for Seniors
  const nfSeniorTargetResolver = (r: Resident) => {
    if (r.level === 3) return nfMeta.targetPGY3 ?? 3;
    if (r.level === 2) return nfMeta.targetPGY2 ?? 4;
    return nfMeta.targetSenior ?? 4;
  };

  // Pass 1: Mandatory Min
  for (let w = 0; w < TOTAL_WEEKS; w++) {
    const assignedResidents = residents.filter(r => newSchedule[r.id][w]?.assignment === AssignmentType.NIGHT_FLOAT);

    // Interns
    const currentInterns = assignedResidents.filter(r => r.level === 1);
    let filledInterns = assignBlock(
        w, AssignmentType.NIGHT_FLOAT, nfMeta.duration, (l) => l === 1,
        Math.max(0, nfMeta.minInterns - currentInterns.length), 
        Math.max(0, nfMeta.minInterns - currentInterns.length),
        nfMeta.targetIntern, [...assignedResidents]
    );
    // Fallback if needed (short blocks)
    if (currentInterns.length + filledInterns < nfMeta.minInterns) {
       let needed = nfMeta.minInterns - (currentInterns.length + filledInterns);
       for (let d = nfMeta.duration - 1; d >= 1; d--) {
          if (needed <= 0) break;
          needed -= assignBlock(w, AssignmentType.NIGHT_FLOAT, d, (l) => l === 1, needed, needed, undefined, [...assignedResidents]);
       }
    }

    // Seniors
    // NOTE: Senior blocks fill the shared "Senior" pool which includes PGY2 and PGY3.
    const currentSeniors = assignedResidents.filter(r => r.level > 1);
    let filledSeniors = assignBlock(
        w, AssignmentType.NIGHT_FLOAT, nfMeta.duration, (l) => l > 1,
        Math.max(0, nfMeta.minSeniors - currentSeniors.length),
        Math.max(0, nfMeta.minSeniors - currentSeniors.length),
        nfSeniorTargetResolver, [...assignedResidents]
    );
    // Fallback
    if (currentSeniors.length + filledSeniors < nfMeta.minSeniors) {
       let needed = nfMeta.minSeniors - (currentSeniors.length + filledSeniors);
       for (let d = nfMeta.duration - 1; d >= 1; d--) {
          if (needed <= 0) break;
          needed -= assignBlock(w, AssignmentType.NIGHT_FLOAT, d, (l) => l > 1, needed, needed, undefined, [...assignedResidents]);
       }
    }
  }

  // Pass 2: Fill extra capacity up to targets
  const shuffledWeeks = Array.from({length: TOTAL_WEEKS}, (_, i) => i).sort(() => Math.random() - 0.5);
  for (const w of shuffledWeeks) {
    const assignedResidents = residents.filter(r => newSchedule[r.id][w]?.assignment === AssignmentType.NIGHT_FLOAT);

    const currentInterns = assignedResidents.filter(r => r.level === 1);
    assignBlock(
        w, AssignmentType.NIGHT_FLOAT, nfMeta.duration, (l) => l === 1,
        0, Math.max(0, nfMeta.maxInterns - currentInterns.length), nfMeta.targetIntern, [...assignedResidents]
    );

    const currentSeniors = assignedResidents.filter(r => r.level > 1);
    assignBlock(
        w, AssignmentType.NIGHT_FLOAT, nfMeta.duration, (l) => l > 1,
        0, Math.max(0, nfMeta.maxSeniors - currentSeniors.length), nfSeniorTargetResolver, [...assignedResidents]
    );
  }

  // 3. FILL CORE ROTATIONS (ICU, Wards)
  const coreTypes = [AssignmentType.ICU, AssignmentType.WARDS_RED, AssignmentType.WARDS_BLUE];
  for (let w = 0; w < TOTAL_WEEKS; w++) {
    for (const type of coreTypes) {
      const meta = ROTATION_METADATA[type];
      const assignedResidents = residents.filter(r => newSchedule[r.id][w]?.assignment === type);

      // Interns
      const currentInterns = assignedResidents.filter(r => r.level === 1);
      let filledInterns = assignBlock(
          w, type, meta.duration, (l) => l === 1, 
          Math.max(0, meta.minInterns - currentInterns.length),
          Math.max(0, meta.maxInterns - currentInterns.length),
          meta.targetIntern, [...assignedResidents]
      );
      // Fallback
      if (currentInterns.length + filledInterns < meta.minInterns) {
           let needed = meta.minInterns - (currentInterns.length + filledInterns);
           for (let d = meta.duration - 1; d >= 1; d--) {
              if (needed <= 0) break;
              needed -= assignBlock(w, type, d, (l) => l === 1, needed, needed, undefined, [...assignedResidents]);
           }
      }

      // Seniors
      const currentSeniors = assignedResidents.filter(r => r.level > 1);
      let filledSeniors = assignBlock(
          w, type, meta.duration, (l) => l > 1, 
          Math.max(0, meta.minSeniors - currentSeniors.length),
          Math.max(0, meta.maxSeniors - currentSeniors.length),
          meta.targetSenior, [...assignedResidents]
      );
      // Fallback
      if (currentSeniors.length + filledSeniors < meta.minSeniors) {
           let needed = meta.minSeniors - (currentSeniors.length + filledSeniors);
           for (let d = meta.duration - 1; d >= 1; d--) {
              if (needed <= 0) break;
              needed -= assignBlock(w, type, d, (l) => l > 1, needed, needed, undefined, [...assignedResidents]);
           }
      }
    }
  }

  // 4. REQUIRED ELECTIVES / ROTATIONS
  const pgy1Reqs = [AssignmentType.CARDS, AssignmentType.ID, AssignmentType.NEPH, AssignmentType.PULM];
  const pgy2Reqs = [AssignmentType.ONC, AssignmentType.NEURO, AssignmentType.RHEUM];
  const pgy3Reqs = [AssignmentType.ADD_MED, AssignmentType.ENDO, AssignmentType.GERI, AssignmentType.HPC];

  const concurrencyPasses = [1, 10]; 

  for (const limit of concurrencyPasses) {
      const passWeeks = Array.from({length: TOTAL_WEEKS}, (_, i) => i).sort(() => Math.random() - 0.5);
      for (const w of passWeeks) {

        // PGY1
        for (const type of pgy1Reqs) {
          const meta = ROTATION_METADATA[type];
          const assigned = residents.filter(r => newSchedule[r.id][w]?.assignment === type);
          const currentCount = assigned.length;
          const effectiveMax = Math.min(meta.maxInterns, limit); // PGY1 electives are usually just interns
          if (currentCount < effectiveMax) {
             assignBlock(w, type, meta.duration, (l) => l === 1, 0, effectiveMax - currentCount, meta.targetIntern, [...assigned]);
          }
        }

        // PGY2
        for (const type of pgy2Reqs) {
          const meta = ROTATION_METADATA[type];
          const assigned = residents.filter(r => newSchedule[r.id][w]?.assignment === type);
          const currentCount = assigned.length;
          // Note: Required PGY2 rotations target seniors. Using maxSeniors.
          const effectiveMax = Math.min(meta.maxSeniors, limit);
          if (currentCount < effectiveMax) {
              assignBlock(w, type, meta.duration, (l) => l === 2, 0, effectiveMax - currentCount, meta.targetSenior, [...assigned]);
          }
        }

        // PGY3
        for (const type of pgy3Reqs) {
          const meta = ROTATION_METADATA[type];
          const assigned = residents.filter(r => newSchedule[r.id][w]?.assignment === type);
          const currentCount = assigned.length;
          const effectiveMax = Math.min(meta.maxSeniors, limit);
          if (currentCount < effectiveMax) {
              assignBlock(w, type, meta.duration, (l) => l === 3, 0, effectiveMax - currentCount, meta.targetSenior, [...assigned]);
          }
        }
      }
  }

  // 5. FILL EM (Emergency Medicine)
  const emMeta = ROTATION_METADATA[AssignmentType.EM];
  for (let w = 0; w < TOTAL_WEEKS; w++) {
    const assignedResidents = residents.filter(r => newSchedule[r.id][w]?.assignment === AssignmentType.EM);

    // Interns
    const currentInterns = assignedResidents.filter(r => r.level === 1);
    let filledInterns = assignBlock(
        w, AssignmentType.EM, emMeta.duration, (l) => l === 1, 
        Math.max(0, emMeta.minInterns - currentInterns.length),
        Math.max(0, emMeta.maxInterns - currentInterns.length),
        emMeta.targetIntern, [...assignedResidents]
    );
    // Fallback
    if (currentInterns.length + filledInterns < emMeta.minInterns) {
         let needed = emMeta.minInterns - (currentInterns.length + filledInterns);
         for (let d = emMeta.duration - 1; d >= 1; d--) {
            if (needed <= 0) break;
            needed -= assignBlock(w, AssignmentType.EM, d, (l) => l === 1, needed, needed, emMeta.targetIntern, [...assignedResidents]);
         }
    }

    // Seniors
    const currentSeniors = assignedResidents.filter(r => r.level > 1);
    let filledSeniors = assignBlock(
        w, AssignmentType.EM, emMeta.duration, (l) => l > 1, 
        Math.max(0, emMeta.minSeniors - currentSeniors.length),
        Math.max(0, emMeta.maxSeniors - currentSeniors.length),
        emMeta.targetSenior, [...assignedResidents]
    );
    // Fallback
    if (currentSeniors.length + filledSeniors < emMeta.minSeniors) {
         let needed = emMeta.minSeniors - (currentSeniors.length + filledSeniors);
         for (let d = emMeta.duration - 1; d >= 1; d--) {
            if (needed <= 0) break;
            needed -= assignBlock(w, AssignmentType.EM, d, (l) => l > 1, needed, needed, undefined, [...assignedResidents]);
         }
    }
  }

  // 6. FILL GAPS WITH GENERIC ELECTIVES
  residents.forEach(r => {
    for (let w = 0; w < TOTAL_WEEKS; w++) {
        if (!newSchedule[r.id][w].assignment) {
            newSchedule[r.id][w] = { assignment: AssignmentType.ELECTIVE, locked: false };
        }
    }
  });

  return newSchedule;
};

export const calculateStats = (residents: Resident[], schedule: ScheduleGrid): ScheduleStats => {
  const stats: ScheduleStats = {};

  // Create safe default object from all AssignmentTypes
  const createDefaultStats = () => {
      const obj: Record<AssignmentType, number> = {} as any;
      Object.values(AssignmentType).forEach(t => obj[t] = 0);
      return obj;
  };

  residents.forEach(r => {
    stats[r.id] = createDefaultStats();

    if (schedule[r.id]) {
      schedule[r.id].forEach(cell => {
        if (cell.assignment && stats[r.id][cell.assignment] !== undefined) {
          stats[r.id][cell.assignment]++;
        }
      });
    }
  });

  return stats;
};

// New Helper for Diversity
export const calculateDiversityStats = (residents: Resident[], schedule: ScheduleGrid): Record<string, number> => {
    const interactions: Record<string, Set<string>> = {};
    residents.forEach(r => interactions[r.id] = new Set());

    const relevantTypes = [
      AssignmentType.WARDS_RED,
      AssignmentType.WARDS_BLUE,
      AssignmentType.ICU,
      AssignmentType.NIGHT_FLOAT,
      AssignmentType.EM,
      AssignmentType.CLINIC,
      AssignmentType.MET_WARDS,
      AssignmentType.METRO,
    ];

    for (let w = 0; w < TOTAL_WEEKS; w++) {
      const byAssignment: Record<string, string[]> = {};

      residents.forEach(r => {
        const type = schedule[r.id]?.[w]?.assignment;
        if (type && relevantTypes.includes(type)) {
          if (!byAssignment[type]) byAssignment[type] = [];
          byAssignment[type].push(r.id);
        }
      });

      Object.values(byAssignment).forEach(group => {
        if (group.length < 2) return;
        for (let i = 0; i < group.length; i++) {
          for (let j = i + 1; j < group.length; j++) {
            const r1 = group[i];
            const r2 = group[j];
            interactions[r1].add(r2);
            interactions[r2].add(r1);
          }
        }
      });
    }

    const results: Record<string, number> = {};
    const totalPossible = Math.max(1, residents.length - 1);

    residents.forEach(r => {
        results[r.id] = (interactions[r.id].size / totalPossible) * 100;
    });

    return results;
};

export const calculateFairnessMetrics = (residents: Resident[], schedule: ScheduleGrid): CohortFairnessMetrics[] => {
    // 1. Calculate raw counts per resident
    const residentCounts: ResidentFairnessMetrics[] = residents.map(r => {
        let coreWeeks = 0;
        let requiredWeeks = 0;
        let electiveWeeks = 0;
        let vacationWeeks = 0;

        let totalIntensityScore = 0;
        let maxIntensityStreak = 0;
        let currentIntensityStreak = 0;

        const cells = schedule[r.id] || [];

        for (let i = 0; i < TOTAL_WEEKS; i++) {
            const assign = cells[i]?.assignment;

            if (assign) {
                const meta = ROTATION_METADATA[assign];

                // Counts
                if (CORE_TYPES.includes(assign)) {
                    coreWeeks++;
                } else if (REQUIRED_TYPES.includes(assign)) {
                    requiredWeeks++;
                } else if (ELECTIVE_TYPES.includes(assign)) {
                    electiveWeeks++;
                } else if (assign === VACATION_TYPE) {
                    vacationWeeks++;
                }

                // Intensity Calc
                if (meta) {
                    totalIntensityScore += meta.intensity;

                    // Streak Calc (Intensity >= 3 is "Intense")
                    if (meta.intensity >= 3) {
                        currentIntensityStreak++;
                    } else {
                        // Check for 1-week grace period (bridge)
                        // If we are in a streak, the current week is low intensity, but the NEXT week is high intensity
                        // We count this week as part of the streak to represent lack of recovery.
                        let bridged = false;
                        if (currentIntensityStreak > 0 && i < TOTAL_WEEKS - 1) {
                            const nextAssign = cells[i+1]?.assignment;
                            if (nextAssign) {
                                const nextMeta = ROTATION_METADATA[nextAssign];
                                if (nextMeta && nextMeta.intensity >= 3) {
                                    currentIntensityStreak++;
                                    bridged = true;
                                }
                            }
                        }

                        if (!bridged) {
                            if (currentIntensityStreak > maxIntensityStreak) {
                                maxIntensityStreak = currentIntensityStreak;
                            }
                            currentIntensityStreak = 0;
                        }
                    }
                }
            }
        }
        // Check streak at end
        if (currentIntensityStreak > maxIntensityStreak) {
            maxIntensityStreak = currentIntensityStreak;
        }

        return {
            id: r.id,
            name: r.name,
            level: r.level,
            coreWeeks,
            requiredWeeks,
            electiveWeeks,
            vacationWeeks,
            totalIntensityScore,
            maxIntensityStreak
        };
    });

    // 2. Group by PGY and calculate stats
    const pgyGroups = [1, 2, 3].map(level => {
        const group = residentCounts.filter(r => r.level === level);
        const count = group.length || 1;

        // Calculate Means
        const meanCore = group.reduce((sum, r) => sum + r.coreWeeks, 0) / count;
        const meanElective = group.reduce((sum, r) => sum + r.electiveWeeks, 0) / count;
        const meanIntensity = group.reduce((sum, r) => sum + r.totalIntensityScore, 0) / count;

        // Calculate StDev (Population)
        const sdCore = Math.sqrt(group.reduce((sum, r) => sum + Math.pow(r.coreWeeks - meanCore, 2), 0) / count);
        const sdElective = Math.sqrt(group.reduce((sum, r) => sum + Math.pow(r.electiveWeeks - meanElective, 2), 0) / count);
        const sdIntensity = Math.sqrt(group.reduce((sum, r) => sum + Math.pow(r.totalIntensityScore - meanIntensity, 2), 0) / count);

        // Fairness Score: Penalize deviation in Core (Workload) and Elective (Flexibility)
        const fairnessScore = Math.round(Math.max(0, 100 - (sdCore * 8) - (sdElective * 4)));

        return {
            level,
            residents: group,
            meanCore, sdCore,
            meanElective, sdElective,
            meanIntensity, sdIntensity,
            fairnessScore
        };
    });

    return pgyGroups;
}
